// LoadCarClass loads the resultEntry's CarClass into the .R struct
func (os ResultEntrySlice) LoadCarClass(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if len(os) == 0 {
		return nil
	}

	carClasses, err := os.CarClass(mods...).All(ctx, exec)
	if err != nil {
		return err
	}

	for _, o := range os {
		if o == nil {
			continue
		}

		o.R.CarClass = nil
		o.R.Loaded.CarClass = true
	}
	// O(N+M) stitch via a map keyed by the join column (key -> []parent; was O(N*M)).
	resultEntryByKey := make(map[int32][]*ResultEntry, len(os))
	for _, o := range os {
		if o == nil {
			continue
		}

		// NULL never matches any row in SQL, so don't add it to the map
		if !o.CarClassID.IsValue() {
			continue
		}

		resultEntryByKey[o.CarClassID.MustGet()] = append(resultEntryByKey[o.CarClassID.MustGet()], o)
	}

	for _, rel := range carClasses {

		owners, ok := resultEntryByKey[rel.ID]
		if !ok {
			continue
		}

		for _, o := range owners {

			// to-one: keep only the first matching child (matches the previous break)
			if o.R.CarClass != nil {
				continue
			}

			rel.R.ResultEntries = append(rel.R.ResultEntries, o)

			o.R.CarClass = rel

		}
	}

	return nil
}

