// LoadTeam loads the resultEntry's Team into the .R struct
func (os ResultEntrySlice) LoadTeam(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if len(os) == 0 {
		return nil
	}

	teams, err := os.Team(mods...).All(ctx, exec)
	if err != nil {
		return err
	}

	for _, o := range os {
		if o == nil {
			continue
		}

		o.R.Team = nil
		o.R.Loaded.Team = true
	}
	// O(N+M) stitch via a map keyed by the join column (key -> []parent; was O(N*M)).
	resultEntryByKey := make(map[int32][]*ResultEntry, len(os))
	for _, o := range os {
		if o == nil {
			continue
		}

		// NULL never matches any row in SQL, so don't add it to the map
		if !o.TeamID.IsValue() {
			continue
		}

		resultEntryByKey[o.TeamID.MustGet()] = append(resultEntryByKey[o.TeamID.MustGet()], o)
	}

	for _, rel := range teams {

		owners, ok := resultEntryByKey[rel.ID]
		if !ok {
			continue
		}

		for _, o := range owners {

			// to-one: keep only the first matching child (matches the previous break)
			if o.R.Team != nil {
				continue
			}

			rel.R.ResultEntries = append(rel.R.ResultEntries, o)

			o.R.Team = rel

		}
	}

	return nil
}

type resultEntryJoins[Q dialect.Joinable] struct {
	typ      string
	CarClass modAs[Q, carClassColumns]
	CarModel modAs[Q, carModelColumns]
	Driver   modAs[Q, driverColumns]
	RaceGrid modAs[Q, raceGridColumns]
	Team     modAs[Q, teamColumns]
}

func (j resultEntryJoins[Q]) aliasedAs(alias string) resultEntryJoins[Q] {
	return buildResultEntryJoins[Q](buildResultEntryColumns(alias), j.typ)
}

func buildResultEntryJoins[Q dialect.Joinable](cols resultEntryColumns, typ string) resultEntryJoins[Q] {
	return resultEntryJoins[Q]{
		typ: typ,
		CarClass: modAs[Q, carClassColumns]{
			c: CarClasses.Columns,
			f: func(to carClassColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, CarClasses.NameExpr().As(to.Alias())).On(
						to.ID.EQ(cols.CarClassID),
					))
				}

				return mods
			},
		},
		CarModel: modAs[Q, carModelColumns]{
			c: CarModels.Columns,
			f: func(to carModelColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, CarModels.NameExpr().As(to.Alias())).On(
						to.ID.EQ(cols.CarModelID),
					))
				}

				return mods
			},
		},
		Driver: modAs[Q, driverColumns]{
			c: Drivers.Columns,
			f: func(to driverColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, Drivers.NameExpr().As(to.Alias())).On(
						to.ID.EQ(cols.DriverID),
					))
				}

				return mods
			},
		},
		RaceGrid: modAs[Q, raceGridColumns]{
			c: RaceGrids.Columns,
			f: func(to raceGridColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, RaceGrids.NameExpr().As(to.Alias())).On(
						to.ID.EQ(cols.RaceGridID),
					))
				}

				return mods
			},
		},
		Team: modAs[Q, teamColumns]{
			c: Teams.Columns,
			f: func(to teamColumns) bob.Mod[Q] {
				mods := make(mods.QueryMods[Q], 0, 1)

				{
					mods = append(mods, dialect.Join[Q](typ, Teams.NameExpr().As(to.Alias())).On(
						to.ID.EQ(cols.TeamID),
					))
				}

				return mods
			},
		},
	}
}
